INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('storybuilder', 'starter', '{"de":{"text":"Es war einmal an einem völlig normalen Montag, als..."},"en":{"text":"It was a perfectly normal Monday when..."},"es":{"text":"Era un lunes completamente normal cuando..."},"fr":{"text":"Il était une fois, un lundi tout à fait normal, quand..."},"it":{"text":"C''era una volta, in un lunedi del tutto normale, quando..."},"nl":{"text":"Er was eens op een doodgewone maandag, toen..."},"pl":{"text":"Pewnego zupełnie zwyczajnego poniedziałku stało się tak, że..."},"pt":{"text":"Era uma vez em uma segunda-feira totalmente normal, quando..."},"tr":{"text":"Bir zamanlar tamamen normal bir pazartesi gunu, birden..."},"ar":{"text":"ذات يوم إثنين عادي تماماً..."}}', 'medium', 'general', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('storybuilder', 'starter', '{"de":{"text":"Niemand hätte gedacht, dass ausgerechnet heute..."},"en":{"text":"Nobody would have thought that today of all days..."},"es":{"text":"Nadie habria pensado que precisamente hoy..."},"fr":{"text":"Personne n''aurait pensé qu''aujourd''hui justement..."},"it":{"text":"Nessuno avrebbe mai pensato che proprio oggi..."},"nl":{"text":"Niemand had gedacht dat uitgerekend vandaag..."},"pl":{"text":"Nikt by nie pomyślał, że akurat dzisiaj..."},"pt":{"text":"Ninguem imaginava que justamente hoje..."},"tr":{"text":"Kimse bugun boyle bir seyin olacagini dusunmezdi..."},"ar":{"text":"لم يكن أحد يتوقع أن اليوم بالذات..."}}', 'medium', 'general', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('storybuilder', 'starter', '{"de":{"text":"Als die Uhr Mitternacht schlug, passierte etwas Unerwartetes:"},"en":{"text":"When the clock struck midnight, something unexpected happened:"},"es":{"text":"Cuando el reloj marco la medianoche, paso algo inesperado:"},"fr":{"text":"Quand l''horloge sonna minuit, quelque chose d''inattendu se produisit :"},"it":{"text":"Quando l''orologio segno la mezzanotte, accadde qualcosa di inaspettato:"},"nl":{"text":"Toen de klok middernacht sloeg, gebeurde er iets onverwachts:"},"pl":{"text":"Kiedy zegar wybił północ, wydarzyło się coś niespodziewanego:"},"pt":{"text":"Quando o relogio bateu meia-noite, algo inesperado aconteceu:"},"tr":{"text":"Saat gece yarisi vurdiginda beklenmedik bir sey oldu:"},"ar":{"text":"عندما دقت الساعة منتصف الليل، حدث شيء غير متوقع:"}}', 'medium', 'general', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('storybuilder', 'starter', '{"de":{"text":"In einer kleinen Stadt am Rande der Welt lebte..."},"en":{"text":"In a small town at the edge of the world lived..."},"es":{"text":"En un pequeno pueblo al borde del mundo vivia..."},"fr":{"text":"Dans une petite ville au bout du monde vivait..."},"it":{"text":"In una piccola citta ai confini del mondo viveva..."},"nl":{"text":"In een klein stadje aan de rand van de wereld woonde..."},"pl":{"text":"W małym miasteczku na krańcu świata mieszkał..."},"pt":{"text":"Em uma pequena cidade no fim do mundo vivia..."},"tr":{"text":"Dunyanin ucundaki kucuk bir kasabada yasayan..."},"ar":{"text":"في بلدة صغيرة على حافة العالم كان يعيش..."}}', 'medium', 'general', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('storybuilder', 'starter', '{"de":{"text":"Der Brief kam ohne Absender und enthielt nur einen Satz:"},"en":{"text":"The letter arrived without a return address and contained only one sentence:"},"es":{"text":"La carta llego sin remitente y contenia solo una frase:"},"fr":{"text":"La lettre arriva sans expéditeur et ne contenait qu''une phrase :"},"it":{"text":"La lettera arrivo senza mittente e conteneva una sola frase:"},"nl":{"text":"De brief kwam zonder afzender en bevatte slechts een zin:"},"pl":{"text":"List przyszedł bez nadawcy i zawierał tylko jedno zdanie:"},"pt":{"text":"A carta veio sem remetente e continha apenas uma frase:"},"tr":{"text":"Mektup gondericisiz geldi ve icinde sadece bir cumle vardi:"},"ar":{"text":"وصلت الرسالة بدون مُرسِل وتحتوي على جملة واحدة فقط:"}}', 'medium', 'general', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('storybuilder', 'starter', '{"de":{"text":"Alles begann mit einem merkwuerdigen Geraeusch im Kuehlschrank."},"en":{"text":"It all started with a strange noise in the refrigerator."},"es":{"text":"Todo empezo con un sonido extrano en la nevera."},"fr":{"text":"Tout commença par un bruit étrange dans le réfrigérateur."},"it":{"text":"Tutto comincio con uno strano rumore nel frigorifero."},"nl":{"text":"Alles begon met een vreemd geluid in de koelkast."},"pl":{"text":"Wszystko zaczęło się od dziwnego dźwięku z lodówki."},"pt":{"text":"Tudo comecou com um barulho estranho na geladeira."},"tr":{"text":"Her sey buzdolabindan gelen garip bir sesle basladi."},"ar":{"text":"بدأ كل شيء بصوت غريب من الثلاجة."}}', 'medium', 'general', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('storybuilder', 'starter', '{"de":{"text":"Es regnete Gummibärchen, und niemand wusste warum."},"en":{"text":"It was raining gummy bears, and nobody knew why."},"es":{"text":"Llovian ositos de goma, y nadie sabia por que."},"fr":{"text":"Il pleuvait des oursons en gélatine, et personne ne savait pourquoi."},"it":{"text":"Piovevano caramelle gommose, e nessuno sapeva il perche."},"nl":{"text":"Het regende gummiberen, en niemand wist waarom."},"pl":{"text":"Padały żelki z nieba i nikt nie wiedział dlaczego."},"pt":{"text":"Estava chovendo jujubas, e ninguem sabia por que."},"tr":{"text":"Gokten yumusak seker yagiyordu ve kimse nedenini bilmiyordu."},"ar":{"text":"أمطرت السماء حلوى الدببة ولم يعرف أحد لماذا."}}', 'medium', 'general', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('storybuilder', 'starter', '{"de":{"text":"Der neue Nachbar hatte ein Geheimnis, das alle ändern würde."},"en":{"text":"The new neighbor had a secret that would change everything."},"es":{"text":"El nuevo vecino tenia un secreto que lo cambiaria todo."},"fr":{"text":"Le nouveau voisin avait un secret qui allait tout changer."},"it":{"text":"Il nuovo vicino aveva un segreto che avrebbe cambiato tutto."},"nl":{"text":"De nieuwe buurman had een geheim dat alles zou veranderen."},"pl":{"text":"Nowy sąsiad miał tajemnicę, która miała wszystko zmienić."},"pt":{"text":"O novo vizinho tinha um segredo que mudaria tudo."},"tr":{"text":"Yeni komsunun her seyi degistirecek bir sirri vardi."},"ar":{"text":"الجار الجديد كان لديه سر سيغير كل شيء."}}', 'medium', 'general', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('storybuilder', 'starter', '{"de":{"text":"Mein Hund sah mich an und sagte plötzlich:"},"en":{"text":"My dog looked at me and suddenly said:"},"es":{"text":"Mi perro me miro y de repente dijo:"},"fr":{"text":"Mon chien me regarda et dit soudainement :"},"it":{"text":"Il mio cane mi guardo e all''improvviso disse:"},"nl":{"text":"Mijn hond keek me aan en zei plotseling:"},"pl":{"text":"Mój pies spojrzał na mnie i nagle powiedział:"},"pt":{"text":"Meu cachorro me olhou e de repente disse:"},"tr":{"text":"Kopegim bana bakti ve birden soyle dedi:"},"ar":{"text":"نظر إليّ كلبي وقال فجأة:"}}', 'medium', 'general', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('storybuilder', 'starter', '{"de":{"text":"Auf dem Dachboden fand ich eine Kiste mit der Aufschrift \"NICHT OEFFNEN\"."},"en":{"text":"In the attic, I found a box labeled \"DO NOT OPEN\"."},"es":{"text":"En el desvan encontre una caja con la etiqueta \"NO ABRIR\"."},"fr":{"text":"Au grenier, je trouvai une boîte marquée « NE PAS OUVRIR »."},"it":{"text":"In soffitta trovai una cassa con la scritta \"NON APRIRE\"."},"nl":{"text":"Op zolder vond ik een kist met het opschrift \"NIET OPENEN\"."},"pl":{"text":"Na strychu znalazłem pudełko z napisem „NIE OTWIERAĆ\"."},"pt":{"text":"No sotao encontrei uma caixa com a inscricao \"NAO ABRA\"."},"tr":{"text":"Tavan arasinda \"ACMA\" yazan bir kutu buldum."},"ar":{"text":"في العلية وجدت صندوقاً مكتوباً عليه \"لا تفتح\"."}}', 'medium', 'general', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('storybuilder', 'starter', '{"de":{"text":"Die Einladung kam per Brieftaube und roch nach Zimt."},"en":{"text":"The invitation arrived by carrier pigeon and smelled of cinnamon."},"es":{"text":"La invitacion llego por paloma mensajera y olia a canela."},"fr":{"text":"L''invitation arriva par pigeon voyageur et sentait la cannelle."},"it":{"text":"L''invito arrivo tramite piccione viaggiatore e profumava di cannella."},"nl":{"text":"De uitnodiging kwam per postduif en rook naar kaneel."},"pl":{"text":"Zaproszenie przyszło pocztą gołębią i pachniało cynamonem."},"pt":{"text":"O convite chegou por pombo-correio e cheirava a canela."},"tr":{"text":"Davetiye posta guverciniyle geldi ve tarcin kokuyordu."},"ar":{"text":"وصلت الدعوة عبر حمام زاجل وكانت تفوح منها رائحة القرفة."}}', 'medium', 'general', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('storybuilder', 'starter', '{"de":{"text":"Als ich aufwachte, stand ein Pinguin neben meinem Bett."},"en":{"text":"When I woke up, a penguin was standing next to my bed."},"es":{"text":"Cuando me desperte, habia un pinguino al lado de mi cama."},"fr":{"text":"Quand je me suis réveillé, un pingouin se tenait à côté de mon lit."},"it":{"text":"Quando mi svegliai, c''era un pinguino accanto al mio letto."},"nl":{"text":"Toen ik wakker werd, stond er een pinguin naast mijn bed."},"pl":{"text":"Kiedy się obudziłem, obok mojego łóżka stał pingwin."},"pt":{"text":"Quando acordei, havia um pinguim ao lado da minha cama."},"tr":{"text":"Uyandığımda yatagimin yaninda bir penguen duruyordu."},"ar":{"text":"عندما استيقظت، كان بطريق يقف بجانب سريري."}}', 'medium', 'general', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('storybuilder', 'starter', '{"de":{"text":"Der Supermarkt hatte geschlossen, also mussten wir..."},"en":{"text":"The supermarket was closed, so we had to..."},"es":{"text":"El supermercado estaba cerrado, asi que tuvimos que..."},"fr":{"text":"Le supermarché était fermé, alors nous avons dû..."},"it":{"text":"Il supermercato era chiuso, quindi dovemmo..."},"nl":{"text":"De supermarkt was dicht, dus moesten we..."},"pl":{"text":"Supermarket był zamknięty, więc musieliśmy..."},"pt":{"text":"O supermercado estava fechado, entao tivemos que..."},"tr":{"text":"Market kapanmisti, bu yuzden mecburen..."},"ar":{"text":"كان السوبرماركت مغلقاً، لذا كان علينا أن..."}}', 'medium', 'general', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('storybuilder', 'starter', '{"de":{"text":"Drei Fremde trafen sich zufaellig im Aufzug und..."},"en":{"text":"Three strangers met by chance in an elevator and..."},"es":{"text":"Tres desconocidos se encontraron por casualidad en un ascensor y..."},"fr":{"text":"Trois inconnus se retrouvèrent par hasard dans l''ascenseur et..."},"it":{"text":"Tre sconosciuti si incontrarono per caso in ascensore e..."},"nl":{"text":"Drie vreemden ontmoetten elkaar toevallig in de lift en..."},"pl":{"text":"Trzech nieznajomych spotkało się przypadkiem w windzie i..."},"pt":{"text":"Tres desconhecidos se encontraram por acaso no elevador e..."},"tr":{"text":"Uc yabanci tesadufen asansorde bulustu ve..."},"ar":{"text":"التقى ثلاثة غرباء بالصدفة في المصعد و..."}}', 'medium', 'general', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('storybuilder', 'starter', '{"de":{"text":"Das Handy klingelte. Auf dem Display stand: \"Du hast 24 Stunden.\""},"en":{"text":"The phone rang. The display read: \"You have 24 hours.\""},"es":{"text":"El telefono sono. En la pantalla decia: \"Tienes 24 horas.\""},"fr":{"text":"Le téléphone sonna. Sur l''écran s''afficha : « Tu as 24 heures. »"},"it":{"text":"Il telefono squillo. Sul display apparve: \"Hai 24 ore.\""},"nl":{"text":"De telefoon ging. Op het scherm stond: \"Je hebt 24 uur.\""},"pl":{"text":"Telefon zadzwonił. Na wyświetlaczu pojawiło się: „Masz 24 godziny.\""},"pt":{"text":"O celular tocou. Na tela dizia: \"Voce tem 24 horas.\""},"tr":{"text":"Telefon caldi. Ekranda yaziyordu: \"24 saatin var.\""},"ar":{"text":"رنّ الهاتف. على الشاشة ظهر: \"لديك 24 ساعة.\""}}', 'medium', 'general', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('storybuilder', 'starter', '{"de":{"text":"Der Kaffee schmeckte heute anders, und plötzlich konnte ich..."},"en":{"text":"The coffee tasted different today, and suddenly I could..."},"es":{"text":"El cafe sabia diferente hoy, y de repente podia..."},"fr":{"text":"Le café avait un goût différent aujourd''hui, et soudain je pouvais..."},"it":{"text":"Il caffe aveva un sapore diverso oggi, e all''improvviso potevo..."},"nl":{"text":"De koffie smaakte vandaag anders, en plotseling kon ik..."},"pl":{"text":"Kawa smakowała dziś inaczej i nagle mogłem..."},"pt":{"text":"O cafe tinha um gosto diferente hoje, e de repente eu podia..."},"tr":{"text":"Kahve bugun farkli geliyordu ve birden yapabiliyordum..."},"ar":{"text":"كان طعم القهوة مختلفاً اليوم، وفجأة أصبحت أستطيع..."}}', 'medium', 'general', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('storybuilder', 'starter', '{"de":{"text":"Als der letzte Gast die Party verliess, bemerkten wir..."},"en":{"text":"When the last guest left the party, we noticed..."},"es":{"text":"Cuando el ultimo invitado se fue de la fiesta, notamos..."},"fr":{"text":"Quand le dernier invité quitta la fête, nous remarquâmes..."},"it":{"text":"Quando l''ultimo ospite lascio la festa, ci accorgemmo che..."},"nl":{"text":"Toen de laatste gast het feest verliet, merkten we..."},"pl":{"text":"Kiedy ostatni gość opuścił imprezę, zauważyliśmy..."},"pt":{"text":"Quando o ultimo convidado saiu da festa, percebemos..."},"tr":{"text":"Son misafir partiyi terk ettiginde fark ettik ki..."},"ar":{"text":"عندما غادر آخر ضيف الحفلة، لاحظنا..."}}', 'medium', 'general', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('storybuilder', 'starter', '{"de":{"text":"Das Navigationsgeraet sagte \"Sie haben Ihr Ziel erreicht\", aber alles was ich sah, war..."},"en":{"text":"The GPS said \"You have reached your destination,\" but all I could see was..."},"es":{"text":"El GPS dijo \"Ha llegado a su destino\", pero todo lo que vi fue..."},"fr":{"text":"Le GPS dit « Vous êtes arrivé à destination », mais tout ce que je voyais, c''était..."},"it":{"text":"Il navigatore disse \"Siete arrivati a destinazione\", ma tutto cio che vedevo era..."},"nl":{"text":"De navigatie zei \"U bent op de bestemming aangekomen\", maar alles wat ik zag was..."},"pl":{"text":"Nawigacja powiedziała „Dotarłeś do celu\", ale wszystko, co widziałem, to..."},"pt":{"text":"O GPS disse \"Voce chegou ao seu destino\", mas tudo que eu via era..."},"tr":{"text":"Navigasyon \"Hedefinize ulastiniz\" dedi, ama tek gordugum..."},"ar":{"text":"قال الملاح \"وصلت إلى وجهتك\"، لكن كل ما رأيته كان..."}}', 'medium', 'general', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('storybuilder', 'starter', '{"de":{"text":"Im Wartezimmer beim Zahnarzt fand ich eine geheimnisvolle Nachricht:"},"en":{"text":"In the dentist''s waiting room, I found a mysterious message:"},"es":{"text":"En la sala de espera del dentista encontre un mensaje misterioso:"},"fr":{"text":"Dans la salle d''attente du dentiste, je trouvai un message mystérieux :"},"it":{"text":"Nella sala d''attesa del dentista trovai un messaggio misterioso:"},"nl":{"text":"In de wachtkamer van de tandarts vond ik een mysterieus bericht:"},"pl":{"text":"W poczekalni u dentysty znalazłem tajemniczą wiadomość:"},"pt":{"text":"Na sala de espera do dentista encontrei uma mensagem misteriosa:"},"tr":{"text":"Disci bekleme odasinda gizemli bir mesaj buldum:"},"ar":{"text":"في غرفة انتظار طبيب الأسنان وجدت رسالة غامضة:"}}', 'medium', 'general', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('storybuilder', 'starter', '{"de":{"text":"Der Paketbote brachte etwas, das niemand bestellt hatte:"},"en":{"text":"The delivery driver brought something nobody had ordered:"},"es":{"text":"El repartidor trajo algo que nadie habia pedido:"},"fr":{"text":"Le livreur apporta quelque chose que personne n''avait commandé :"},"it":{"text":"Il corriere consegno qualcosa che nessuno aveva ordinato:"},"nl":{"text":"De pakketbezorger bracht iets dat niemand had besteld:"},"pl":{"text":"Kurier przyniósł coś, czego nikt nie zamawiał:"},"pt":{"text":"O entregador trouxe algo que ninguem tinha pedido:"},"tr":{"text":"Kargocilar kimsenin siparis etmedigi bir sey getirdi:"},"ar":{"text":"أحضر عامل التوصيل شيئاً لم يطلبه أحد:"}}', 'medium', 'general', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('storybuilder', 'starter', '{"de":{"text":"Mitten im Meeting fiel die Maske meines Chefs — im woertlichen Sinne."},"en":{"text":"In the middle of the meeting, my boss''s mask fell off — literally."},"es":{"text":"En medio de la reunion, la mascara de mi jefe se cayo — literalmente."},"fr":{"text":"En pleine réunion, le masque de mon chef tomba — au sens propre."},"it":{"text":"Nel bel mezzo della riunione, la maschera del mio capo cadde — letteralmente."},"nl":{"text":"Midden in de vergadering viel het masker van mijn baas — letterlijk."},"pl":{"text":"W środku spotkania maska mojego szefa spadła — dosłownie."},"pt":{"text":"No meio da reuniao, a mascara do meu chefe caiu — literalmente."},"tr":{"text":"Toplantiinin ortasinda patronumun maskesi dustu — kelimenin tam anlamiyla."},"ar":{"text":"في منتصف الاجتماع، سقط قناع مديري — حرفياً."}}', 'medium', 'general', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('storybuilder', 'starter', '{"de":{"text":"Die Katze brachte etwas nach Hause, das definitiv nicht normal war."},"en":{"text":"The cat brought something home that was definitely not normal."},"es":{"text":"El gato trajo algo a casa que definitivamente no era normal."},"fr":{"text":"Le chat ramena quelque chose à la maison qui n''était définitivement pas normal."},"it":{"text":"Il gatto porto a casa qualcosa che decisamente non era normale."},"nl":{"text":"De kat bracht iets mee naar huis dat absoluut niet normaal was."},"pl":{"text":"Kot przyniósł do domu coś, co zdecydowanie nie było normalne."},"pt":{"text":"O gato trouxe algo para casa que definitivamente nao era normal."},"tr":{"text":"Kedi eve kesinlikle normal olmayan bir sey getirdi."},"ar":{"text":"القطة أحضرت شيئاً للمنزل لم يكن طبيعياً بالتأكيد."}}', 'medium', 'general', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('storybuilder', 'starter', '{"de":{"text":"Als ich mein altes Schulheft aufschlug, fiel ein Zettel heraus mit..."},"en":{"text":"When I opened my old school notebook, a note fell out with..."},"es":{"text":"Cuando abri mi viejo cuaderno del colegio, cayo una nota con..."},"fr":{"text":"Quand j''ouvris mon vieux cahier d''école, un papier en tomba avec..."},"it":{"text":"Quando aprii il mio vecchio quaderno di scuola, cadde un biglietto con..."},"nl":{"text":"Toen ik mijn oude schoolschrift opensloeg, viel er een briefje uit met..."},"pl":{"text":"Kiedy otworzyłem stary zeszyt szkolny, wypadła kartka z..."},"pt":{"text":"Quando abri meu caderno antigo da escola, caiu um bilhete com..."},"tr":{"text":"Eski okul defterimi actigimda icinden bir kagit dustu:"},"ar":{"text":"عندما فتحت دفتري المدرسي القديم، سقطت ورقة مكتوب عليها..."}}', 'medium', 'general', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('storybuilder', 'starter', '{"de":{"text":"Der Fahrstuhl blieb zwischen zwei Stockwerken stecken, und mein Mitfahrer sagte:"},"en":{"text":"The elevator got stuck between two floors, and my fellow passenger said:"},"es":{"text":"El ascensor se quedo atrapado entre dos pisos, y mi companero dijo:"},"fr":{"text":"L''ascenseur resta coincé entre deux étages, et mon co-passager dit :"},"it":{"text":"L''ascensore si blocco tra due piani, e il mio compagno di viaggio disse:"},"nl":{"text":"De lift bleef steken tussen twee verdiepingen, en mijn medepassagier zei:"},"pl":{"text":"Winda zatrzymała się między piętrami, a mój współpasażer powiedział:"},"pt":{"text":"O elevador parou entre dois andares, e meu companheiro disse:"},"tr":{"text":"Asansor iki kat arasinda kaldi ve yanımdaki kisi soyle dedi:"},"ar":{"text":"توقف المصعد بين طابقين، وقال رفيقي في المصعد:"}}', 'medium', 'general', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('storybuilder', 'starter', '{"de":{"text":"Um Punkt Mitternacht leuchtete mein Handy auf — eine Nachricht von mir selbst."},"en":{"text":"At exactly midnight, my phone lit up — a message from myself."},"es":{"text":"A medianoche exacta, mi telefono se ilumino — un mensaje de mi mismo."},"fr":{"text":"À minuit pile, mon téléphone s''alluma — un message de moi-même."},"it":{"text":"A mezzanotte in punto il mio telefono si illumino — un messaggio da me stesso."},"nl":{"text":"Om klokslag middernacht lichtte mijn telefoon op — een bericht van mezelf."},"pl":{"text":"Dokładnie o północy mój telefon się zaświecił — wiadomość od mnie samego."},"pt":{"text":"A meia-noite exata, meu celular acendeu — uma mensagem de mim mesmo."},"tr":{"text":"Tam gece yarisi telefonum yandi — kendimden bir mesaj."},"ar":{"text":"في تمام منتصف الليل أضاء هاتفي — رسالة من نفسي."}}', 'medium', 'general', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('storybuilder', 'starter', '{"de":{"text":"Die Kinder fanden im Garten eine Schatztruhe, die..."},"en":{"text":"The kids found a treasure chest in the garden that..."},"es":{"text":"Los ninos encontraron un cofre del tesoro en el jardin que..."},"fr":{"text":"Les enfants trouvèrent dans le jardin un coffre au trésor qui..."},"it":{"text":"I bambini trovarono in giardino un forziere che..."},"nl":{"text":"De kinderen vonden in de tuin een schatkist die..."},"pl":{"text":"Dzieci znalazły w ogrodzie skrzynię ze skarbem, która..."},"pt":{"text":"As criancas encontraram no jardim um bau do tesouro que..."},"tr":{"text":"Cocuklar bahcede icinde su olan bir hazine sandigi buldu..."},"ar":{"text":"وجد الأطفال في الحديقة صندوق كنز..."}}', 'medium', 'general', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('storybuilder', 'starter', '{"de":{"text":"Als das Wifi ausfiel, passierte etwas Unglaubliches:"},"en":{"text":"When the WiFi went out, something incredible happened:"},"es":{"text":"Cuando se fue el wifi, paso algo increible:"},"fr":{"text":"Quand le Wi-Fi tomba en panne, quelque chose d''incroyable se produisit :"},"it":{"text":"Quando cadde il Wi-Fi, accadde qualcosa di incredibile:"},"nl":{"text":"Toen het wifi uitviel, gebeurde er iets ongelooflijks:"},"pl":{"text":"Kiedy Wi-Fi padło, wydarzyło się coś niewiarygodnego:"},"pt":{"text":"Quando o Wi-Fi caiu, algo inacreditavel aconteceu:"},"tr":{"text":"WiFi kesildiginde inanilmaz bir sey oldu:"},"ar":{"text":"عندما انقطع الواي فاي، حدث شيء لا يُصدق:"}}', 'medium', 'general', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('storybuilder', 'starter', '{"de":{"text":"Der Taxifahrer drehte sich um und sagte: \"Ich bringe Sie nicht dahin.\""},"en":{"text":"The taxi driver turned around and said: \"I''m not taking you there.\""},"es":{"text":"El taxista se dio la vuelta y dijo: \"Ahi no le llevo.\""},"fr":{"text":"Le chauffeur de taxi se retourna et dit : « Je ne vous emmène pas là-bas. »"},"it":{"text":"Il tassista si giro e disse: \"Non la porto li.\""},"nl":{"text":"De taxichauffeur draaide zich om en zei: \"Ik breng u daar niet heen.\""},"pl":{"text":"Taksówkarz odwrócił się i powiedział: „Nie zawiozę was tam.\""},"pt":{"text":"O motorista do taxi se virou e disse: \"Nao vou te levar la.\""},"tr":{"text":"Taksici donup soyle dedi: \"Sizi oraya goturmuyorum.\""},"ar":{"text":"استدار سائق التاكسي وقال: \"لن آخذك إلى هناك.\""}}', 'medium', 'general', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('storybuilder', 'starter', '{"de":{"text":"Auf dem Flohmarkt fand ich eine Lampe — und ja, es war ein Dschinn drin."},"en":{"text":"At the flea market, I found a lamp — and yes, there was a genie inside."},"es":{"text":"En el mercadillo encontre una lampara — y si, habia un genio dentro."},"fr":{"text":"Au marché aux puces, je trouvai une lampe — et oui, il y avait un génie dedans."},"it":{"text":"Al mercato delle pulci trovai una lampada — e si, dentro c''era un genio."},"nl":{"text":"Op de vlooienmarkt vond ik een lamp — en ja, er zat een geest in."},"pl":{"text":"Na pchlim targu znalazłem lampę — i tak, był w niej dżin."},"pt":{"text":"No brechó encontrei uma lampada — e sim, tinha um genio dentro."},"tr":{"text":"Bit pazarinda bir lamba buldum — ve evet, icinde bir cin vardi."},"ar":{"text":"في سوق البرغوث وجدت مصباحاً — ونعم، كان بداخله جني."}}', 'medium', 'general', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('storybuilder', 'starter', '{"de":{"text":"Der Strom fiel aus, und im Dunkeln hoerten wir..."},"en":{"text":"The power went out, and in the darkness we heard..."},"es":{"text":"Se fue la luz, y en la oscuridad escuchamos..."},"fr":{"text":"Le courant coupa, et dans l''obscurité nous entendîmes..."},"it":{"text":"Manco la corrente, e nel buio sentimmo..."},"nl":{"text":"De stroom viel uit, en in het donker hoorden we..."},"pl":{"text":"Prąd się wyłączył i w ciemności usłyszeliśmy..."},"pt":{"text":"A luz acabou, e no escuro ouvimos..."},"tr":{"text":"Elektrik kesildi ve karanlikta duyduk ki..."},"ar":{"text":"انقطع التيار الكهربائي، وفي الظلام سمعنا..."}}', 'medium', 'general', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('storybuilder', 'starter', '{"de":{"text":"Mein Spiegelbild bewegte sich plötzlich anders als ich."},"en":{"text":"My reflection in the mirror suddenly moved differently than I did."},"es":{"text":"Mi reflejo en el espejo de repente se movio de forma diferente a mi."},"fr":{"text":"Mon reflet dans le miroir bougea soudainement différemment de moi."},"it":{"text":"Il mio riflesso nello specchio all''improvviso si mosse diversamente da me."},"nl":{"text":"Mijn spiegelbeeld bewoog plotseling anders dan ik."},"pl":{"text":"Moje odbicie w lustrze nagle poruszyło się inaczej niż ja."},"pt":{"text":"Meu reflexo no espelho de repente se moveu diferente de mim."},"tr":{"text":"Aynadaki yansimam birden benden farkli hareket etti."},"ar":{"text":"تحرك انعكاسي في المرآة فجأة بشكل مختلف عني."}}', 'medium', 'general', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('storybuilder', 'starter', '{"de":{"text":"Die letzte Seite des Buches fehlte, also schrieb ich selbst:"},"en":{"text":"The last page of the book was missing, so I wrote my own:"},"es":{"text":"Faltaba la ultima pagina del libro, asi que escribi la mia:"},"fr":{"text":"La dernière page du livre manquait, alors j''écrivis moi-même :"},"it":{"text":"L''ultima pagina del libro mancava, cosi scrissi io:"},"nl":{"text":"De laatste pagina van het boek ontbrak, dus schreef ik zelf:"},"pl":{"text":"Ostatnia strona książki brakowała, więc sam napisałem:"},"pt":{"text":"A ultima pagina do livro estava faltando, entao eu mesmo escrevi:"},"tr":{"text":"Kitabin son sayfasi eksikti, ben de kendim yazdim:"},"ar":{"text":"كانت الصفحة الأخيرة من الكتاب مفقودة، فكتبت بنفسي:"}}', 'medium', 'general', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('storybuilder', 'starter', '{"de":{"text":"Mein Hund bellte die Wand an — und die Wand bellte zurück."},"en":{"text":"My dog barked at the wall — and the wall barked back."},"es":{"text":"Mi perro ladro a la pared — y la pared le ladro de vuelta."},"fr":{"text":"Mon chien aboya contre le mur — et le mur aboya en retour."},"it":{"text":"Il mio cane abbaio al muro — e il muro abbaio a lui."},"nl":{"text":"Mijn hond blafte tegen de muur — en de muur blafte terug."},"pl":{"text":"Mój pies szczekał na ścianę — a ściana szczekała z powrotem."},"pt":{"text":"Meu cachorro latiu para a parede — e a parede latiu de volta."},"tr":{"text":"Kopegim duvara havladi — ve duvar geri havladi."},"ar":{"text":"نبح كلبي على الحائط — والحائط نبح رداً."}}', 'medium', 'general', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('storybuilder', 'starter', '{"de":{"text":"Im Fundbüro lag ein Gegenstand, den es eigentlich nicht geben sollte."},"en":{"text":"At the lost and found office, there was an object that shouldn''t exist."},"es":{"text":"En la oficina de objetos perdidos habia un objeto que no deberia existir."},"fr":{"text":"Au bureau des objets trouvés, il y avait un objet qui ne devrait pas exister."},"it":{"text":"All''ufficio oggetti smarriti c''era un oggetto che non sarebbe dovuto esistere."},"nl":{"text":"Bij het gevonden voorwerpen bureau lag een object dat eigenlijk niet zou mogen bestaan."},"pl":{"text":"W biurze rzeczy znalezionych leżał przedmiot, który nie powinien istnieć."},"pt":{"text":"No achados e perdidos havia um objeto que nao deveria existir."},"tr":{"text":"Kayip esya biirosunda olmamasi gereken bir nesne vardi."},"ar":{"text":"في مكتب المفقودات كان هناك شيء لا ينبغي أن يكون موجوداً."}}', 'medium', 'general', true);
